document.addEventListener("DOMContentLoaded",function(){"use strict";var e=document.getElementById("age"),t=document.getElementById("height"),n=document.getElementById("weight"),l=document.getElementById("calc-btn"),d=document.getElementById("reset-btn"),o=document.getElementById("result"),u=document.getElementById("result-bodyfat"),a=document.getElementById("result-category"),r=document.getElementById("result-bmi"),i=document.getElementById("result-ideal");l.addEventListener("click",function(){var l=parseFloat(e.value),d=parseFloat(t.value),c=parseFloat(n.value),m=function(){for(var e=document.querySelectorAll('input[name="gender"]'),t=0;t<e.length;t++)if(e[t].checked)return e[t].value;return"male"}();if(isNaN(l)||l<18||l>120)alert("年齢を正しく入力してください（18歳以上）。");else if(isNaN(d)||d<100||d>250)alert("身長を正しく入力してください。");else if(isNaN(c)||c<20||c>300)alert("体重を正しく入力してください。");else{var s=function(e,t){var n=e/100;return t/(n*n)}(d,c),g=function(e,t,n){return 1.2*e+.23*t-10.8*("male"===n?1:0)-5.4}(s,l,m),v=function(e,t){return"male"===t?e<10?"やせ":e<15?"標準(-)":e<20?"標準(+)":e<25?"軽肥満":"肥満":e<20?"やせ":e<25?"標準(-)":e<30?"標準(+)":e<35?"軽肥満":"肥満"}(g,m),f=d/100,y=22*f*f;u.textContent=g.toFixed(1)+"%",a.textContent=v,r.textContent=s.toFixed(1),i.textContent=y.toFixed(1)+"kg",o.hidden=!1,o.scrollIntoView({behavior:"smooth"})}}),d.addEventListener("click",function(){e.value="",t.value="",n.value="",o.hidden=!0})});